var xt = function(xml, tag) {
  var o = '<' + tag, c = '</' + tag + '>';
  var s = xml.indexOf(o); if (s === -1) return '';
  var cs = xml.indexOf('>', s) + 1; if (cs === 0) return '';
  var e = xml.indexOf(c, cs); if (e === -1) return '';
  var val = xml.substring(cs, e).trim();
  if (val.indexOf('<![CDATA[') === 0) val = val.substring(9, val.lastIndexOf(']]>')).trim();
  return val;
};
var xat = function(xml, tag) {
  var res = [], o = '<' + tag, c = '</' + tag + '>', pos = 0;
  while (pos < xml.length) {
    var s = xml.indexOf(o, pos); if (s === -1) break;
    var cs = xml.indexOf('>', s) + 1; if (cs === 0) break;
    var e = xml.indexOf(c, cs); if (e === -1) break;
    res.push(xml.substring(cs, e).trim());
    pos = e + c.length;
  }
  return res;
};
var inferSource = function(raw) {
  if (!raw) return 'Unknown';
  var rl = raw.toLowerCase();
  if (rl.indexOf('gujaratsamachar') !== -1) {
    if (rl.indexOf('/ahmedabad') !== -1) return 'Gujarat Samachar — Ahmedabad';
    if (rl.indexOf('/baroda') !== -1) return 'Gujarat Samachar — Baroda';
    if (rl.indexOf('/surat') !== -1) return 'Gujarat Samachar — Surat';
    if (rl.indexOf('/gandhinagar') !== -1) return 'Gujarat Samachar — Gandhinagar';
    if (rl.indexOf('/rajkot') !== -1) return 'Gujarat Samachar — Rajkot';
    return 'Gujarat Samachar';
  }
  if (rl.indexOf('news.google') !== -1) return 'Google News RSS';
  return 'Gujarat News';
};
