  // Fix missing commas between objects: }{ or } {
  repaired = repaired.replace(/\}\s*\{/g, '},{');
  // Fix missing commas between } and " (end of object, start of next key)
  repaired = repaired.replace(/\}\s*"/g, '},"');
  // Strip control characters (keep printable + newline/tab/cr)
