    } else if (Array.isArray(parsed)) {
      for (var g = 0; g < parsed.length; g++) out.push({ json: parsed[g] });
    } else if (parsed.city) {
      out.push({ json: parsed });
    } else {
      // Wrap in case it parsed but has unusual structure
      out.push({ json: parsed });
    }
    continue;
  }

  // ---- LAYER 3: Object-by-object recovery ----
  // Extract individual {...} blocks at the event level and parse each separately
  var recovered = [];
  var depth = 0, objStart = -1;
  for (var c = 0; c < repaired.length; c++) {
    if (repaired[c] === '{') {
      depth++;
