      depth--;
      if (depth === 1 && objStart !== -1) {
        var block = repaired.substring(objStart, c + 1);
        try {
          var obj = JSON.parse(block);
          if (obj.city || obj.locality || obj.eventCategory) {
            recovered.push(obj);
          }
        } catch (blockErr) {
          // Try fixing the individual block
          var fixBlock = block.replace(/,\s*\}/g, '}');
          try {
            var obj2 = JSON.parse(fixBlock);
            if (obj2.city || obj2.locality || obj2.eventCategory) {
              recovered.push(obj2);
            }
          } catch (blockErr2) {
            // skip this broken object
          }
        }
        objStart = -1;
      }
    }
  }

  if (recovered.length > 0) {
    for (var rv = 0; rv < recovered.length; rv++) {
      out.push({ json: recovered[rv] });
    }
  } else {
    // Absolute last resort: return error with raw response for debugging
