      json: {
        city: 'Gujarat',
        locality: 'System',
        eventCategory: 'Parser Error',
        alertZone: 'BLUE',
        alertEmoji: '🔵',
        crisisSummary: 'JSON parse failed after all repair attempts.',
        newsSource: 'System Monitor',
        latitude: 22.2587,
        longitude: 71.1924,
        rawResponse: text.substring(0, 400)
      }
